#!/usr/bin/env python3
"""
Fix Tier C Batch 1a: IDs 47 (Bacalhau à Brás), 49 (Jerk Chicken), 54 (Moules-frites)
Replaces ingredients (quantified) and howIsMade (600–900 ch EN) for all locales.
"""
import re, sys

JS_FILE = "public/js/recipes.js"

def find_recipe_block(content, recipe_id):
    """Return (start, end) of the recipe's JS object block."""
    pattern = re.compile(r'\n  \{\n    id: ' + str(recipe_id) + r',')
    m = pattern.search(content)
    if not m:
        return None, None
    start = m.start()
    depth = 0
    i = start + 1
    while i < len(content):
        c = content[i]
        if c == '{':
            depth += 1
        elif c == '}':
            depth -= 1
            if depth == 0:
                end = i + 1
                if end < len(content) and content[end] == ',':
                    end += 1
                return start, end
        i += 1
    return start, len(content)

def find_field_bounds(block, field):
    """Return (start, end) of `    field: { ... },` within block."""
    pat = re.compile(r'\n    ' + re.escape(field) + r': \{')
    m = pat.search(block)
    if not m:
        return None, None
    brace_start = m.end() - 1
    depth = 1
    i = brace_start + 1
    while i < len(block) and depth > 0:
        if block[i] == '{':
            depth += 1
        elif block[i] == '}':
            depth -= 1
        i += 1
    end = i
    if end < len(block) and block[end] == ',':
        end += 1
    return m.start(), end

def replace_field(content, recipe_id, field, new_lines):
    rb_start, rb_end = find_recipe_block(content, recipe_id)
    if rb_start is None:
        print(f"ERROR: recipe {recipe_id} not found"); return content
    block = content[rb_start:rb_end]
    f_start, f_end = find_field_bounds(block, field)
    if f_start is None:
        print(f"ERROR: field '{field}' not found in recipe {recipe_id}"); return content
    new_field = f'\n    {field}: {{\n{new_lines}\n    }},'
    new_block = block[:f_start] + new_field + block[f_end:]
    print(f"  [OK] recipe {recipe_id} {field} replaced")
    return content[:rb_start] + new_block + content[rb_end:]

