def main():
    with open(JS_FILE, 'r', encoding='utf-8') as f:
        content = f.read()

    fixes = [
        (47, 'ingredients', INGR_47),
        (47, 'howIsMade',   HOW_47),
        (49, 'ingredients', INGR_49),
        (49, 'howIsMade',   HOW_49),
        (54, 'ingredients', INGR_54),
        (54, 'howIsMade',   HOW_54),
    ]

    for recipe_id, field, new_lines in fixes:
        print(f"Patching recipe {recipe_id} / {field}...")
        content = replace_field(content, recipe_id, field, new_lines)

    with open(JS_FILE, 'w', encoding='utf-8') as f:
        f.write(content)

    print("\nDone. Run audit_quality.py and npm run build to verify.")

if __name__ == '__main__':
    main()
